/**
 * n8n Code node
 * Input: items[0].json.message.text (e.g., "btc", "BTC/USDT", " eth  ")
 * Output: { tradingPairSymbol: "BTCUSDT" }
 */

function normalizeBase(base) {
  if (!base) return "";
  // keep letters only for base symbol (e.g., "btc", "btc-spot" -> "BTC")
  return base.replace(/[^a-zA-Z]/g, "").toUpperCase();
}

const out = [];

for (const item of items) {
  const raw =
    (item?.json?.message?.text ??
     item?.json?.text ??
     item?.json?.symbol ??
     "").toString().trim();

  if (!raw) {
    throw new Error("No symbol text found in json.message.text (or json.text / json.symbol).");
  }

  // Handle common inputs: "btc", "BTCUSDT", "btc/usdt", "btc-usdt", " BTC usdt "
  const upper = raw.toUpperCase().replace(/\s+/g, "");
  let symbol = "";

  if (upper.includes("USDT")) {
    // Normalize any delimiter variants to compact form
    const parts = upper.split(/[-_/]/g).filter(Boolean);
    if (parts.length >= 2) {
      const base = normalizeBase(parts[0]);
      symbol = `${base}USDT`;
    } else {
      // Already like "BTCUSDT"
      symbol = upper.replace(/[^A-Z]/g, "");
    }
  } else {
    // User provided just the base asset (e.g., "btc")
    // or something like "btc-spot" -> take only letters before appending USDT
    const base = normalizeBase(upper);
    if (!base) throw new Error("Could not derive base symbol from input.");
    symbol = `${base}USDT`;
  }

  out.push({ json: { tradingPairSymbol: symbol } });
}

return out;

// items: array of input items from the Merge node
// Each item.json is a single candle object

const allCandles = items.map(i => i.json);

// Return ONE output item with the combined array
return [
  {
    json: {
      allCandles
    }
  }
];

const articles = $json.articles || [];
const filteredArticles = articles.map(article => ({
  title: article.title,
  description: article.description,
}));

return [{
  json: {
    filteredArticles
  }
}];

// Initialize containers for each set of data.
const allCandles = [];
let contentData = null;

// Loop over each item from the merge node.
for (const item of items) {
  // If the item has candlestick data, add it to the array.
  if (item.json.allCandles !== undefined) {
    // Assuming item.json.allCandles is an array.
    allCandles.push(...item.json.allCandles);
  }

  // If the item has embedded content (in message.content), store it.
  if (item.json.message && item.json.message.content !== undefined) {
    contentData = item.json.message.content;
  }
}

// Return a single item with both candlestick data and content.
return [{
  json: {
    allCandles,
    content: contentData
  }
}];

/**
 * n8n Code node — Split & Sanitize for Telegram (HTML)
 * Input:  items[0].json.output  (or .message)
 * Output: N items: { message: "<chunk <=4096 chars, HTML-safe>" }
 */

const TELEGRAM_LIMIT = 4096;
const SAFETY = 40;                        // tiny buffer for safety
const MAX = TELEGRAM_LIMIT - SAFETY;
const ALLOWED = ['b','strong','i','em','u','s','del','code','pre','a','tg-spoiler','br'];

/* ---------- Sanitize HTML for Telegram ---------- */
function restoreAllowedTags(str) {
  for (const tag of ALLOWED) {
    // open/close tags
    str = str
      .replaceAll(`&lt;${tag}&gt;`, `<${tag}>`)
      .replaceAll(`&lt;/${tag}&gt;`, `</${tag}>`);
    if (tag === 'br') {
      str = str
        .replaceAll(`&lt;br/&gt;`, `<br/>`)
        .replaceAll(`&lt;br&gt;`, `<br>`);
    }
  }
  // restore <a href="...">
  str = str.replace(/&lt;a\s+href=(&quot;[^&]*&quot;|'[^']*')&gt;/gi, (m, href) => {
    const cleanHref = href.replaceAll('&quot;', '"');
    return `<a href=${cleanHref}>`;
  });
  return str;
}

function sanitizeForTelegramHTML(text) {
  let s = String(text ?? '');
  s = s.replaceAll('&', '&amp;');           // escape & first
  s = s.replaceAll('<', '&lt;').replaceAll('>', '&gt;'); // then < >
  s = restoreAllowedTags(s);               // unescape whitelisted tags
  return s;
}

/* ---------- Chunking (after sanitization) ---------- */
function findCut(t, from, maxLen) {
  let end = Math.min(from + maxLen, t.length);
  if (end >= t.length) return t.length;
  let cut = t.lastIndexOf('\n', end);
  if (cut <= from) cut = t.lastIndexOf(' ', end);
  if (cut <= from) cut = end; // hard cut
  return cut;
}

/* ---------- Main ---------- */
const input = (items[0]?.json?.message ?? items[0]?.json?.output ?? '').toString();
const safe = sanitizeForTelegramHTML(input);

if (safe.length <= MAX) {
  return [{ json: { message: safe.trim() } }];
}

const out = [];
let pos = 0;
while (pos < safe.length) {
  const cut = findCut(safe, pos, MAX);
  let chunk = safe.slice(pos, cut).trim();

  // Final hard cap (paranoia)
  if (chunk.length > TELEGRAM_LIMIT) chunk = chunk.slice(0, TELEGRAM_LIMIT);

  out.push({ json: { message: chunk } });
  pos = cut;
}

// Ensure at least one item
if (out.length === 0) out.push({ json: { message: '' } });
return out;
